import scala.xml._
import scala.io.Source

case class Setting(key: String, value: String)

object ConfigService {
  def loadConfig(filePath: String): Map[String, Setting] = {
    val xml = XML.loadFile(filePath)
    val settings = (xml \ "setting").map { setting =>
      val key = (setting \ "key").text
      val value = (setting \ "value").text
      Setting(key, value)
    }.toMap
    settings
  }

  def parseAPIRequest(xmlString: String): Map[String, Setting] = {
    val xml = XML.loadString(xmlString)
    val settings = (xml \ "setting").map { setting =>
      val key = (setting \ "key").text
      val value = (setting \ "value").text
      Setting(key, value)
    }.toMap
    settings
  }
}